// The safe, off-by-one-proof template for binary search:
int binarySearch(List<int> a, int target) {
  int lo = 0, hi = a.length - 1;
  while (lo <= hi) {
    // (lo + hi) ~/ 2 can overflow for very large arrays. This is safer:
    final mid = lo + (hi - lo) ~/ 2;
    if      (a[mid] == target) return mid;
    else if (a[mid] <  target) lo = mid + 1;   // target is to the right
    else                       hi = mid - 1;   // target is to the left
  }
  return -1;   // not found
}

// Fibonacci — naive recursion. O(2^n). n=45 already takes forever.
int fibSlow(int n) => n < 2 ? n : fibSlow(n-1) + fibSlow(n-2);

// Same idea + memoization → O(n). n=1000 is instant.
final cache = <int, int>{};
int fibFast(int n) {
  if (n < 2) return n;
  return cache[n] ??= fibFast(n-1) + fibFast(n-2);
}

// Or bottom-up (tabulation) — also O(n), no recursion at all.
int fibIter(int n) {
  var a = 0, b = 1;
  for (var i = 0; i < n; i++) { final t = a + b; a = b; b = t; }
  return a;
}

// The idea generalizes:
//   NAIVE recursion + repeated subproblems → cache them → linear time.
// That's memoization (top-down DP) or tabulation (bottom-up DP).

// File: search_demo.dart
// Run: dart search_demo.dart
import 'dart:math';

int linearSearch(List<int> a, int target) {
  for (var i = 0; i < a.length; i++) {
    if (a[i] == target) return i;
  }
  return -1;
}

int binarySearch(List<int> a, int target) {
  int lo = 0, hi = a.length - 1;
  while (lo <= hi) {
    final mid = lo + (hi - lo) ~/ 2;
    if      (a[mid] == target) return mid;
    else if (a[mid] <  target) lo = mid + 1;
    else                       hi = mid - 1;
  }
  return -1;
}

void main() {
  final n = 10000000;                       // 10 million entries
  final list = List.generate(n, (i) => i);  // sorted 0..n-1
  final target = n - 3;                     // near the end (worst case for linear)

  var t = DateTime.now();
  for (var i = 0; i < 100; i++) linearSearch(list, target);   // 100 runs
  final linMs = DateTime.now().difference(t).inMilliseconds;

  t = DateTime.now();
  for (var i = 0; i < 100; i++) binarySearch(list, target);
  final binMs = DateTime.now().difference(t).inMilliseconds;

  print('100 linear searches of 10,000,000 items: $linMs ms');
  print('100 binary searches of 10,000,000 items: $binMs ms');
  print('Speedup: ~${(linMs / max(binMs, 1)).toStringAsFixed(0)}x');
}

// Typical output on a laptop:
//   100 linear searches of 10,000,000 items: 5340 ms
//   100 binary searches of 10,000,000 items: 1 ms
//   Speedup: ~5000x
//
// Both find the SAME index. But binary search only reads log₂(10M) ≈ 24 elements per search.
// Linear search reads up to 10 million.
// That's the power of picking the right algorithm on the right data.
